proof_block:
// The ensures contain six `forall` clauses (three over Pcid, three over
// IOid) duplicated for `post1_self_` and `post2_self_`. Each pair has
// triggers that only mention one side (e.g. `post1_self_.pcid_active(p)`
// vs `post2_self_.pcid_active(p)`), so z3 instantiates the two foralls
// at different points and can't line them up to discharge
// `det_pagetable_map_4k_page_equal`. Below we prove, for each pair, a
// single bridge forall carrying *both* sides as alternative triggers,
// so that whichever side appears in the determinism obligation will
// instantiate the bridge and pull in the matching post1/post2 equality.

// pcid_active matches between the two post-states.
assert forall|p: Pcid|
    #![trigger post1_self_.pcid_active(p)]
    #![trigger post2_self_.pcid_active(p)]
    post1_self_.pcid_active(p) == post2_self_.pcid_active(p)
by {
    // post1 ensures gives post1.pcid_active(p) == pre.pcid_active(p)
    // (fires on `post1_self_.pcid_active(p)` in the goal).
    // post2 ensures gives post2.pcid_active(p) == pre.pcid_active(p)
    // (fires on `post2_self_.pcid_active(p)` in the goal).
}

// pcid_to_proc_ptr matches when active.
assert forall|p: Pcid|
    #![trigger post1_self_.pcid_to_proc_ptr(p)]
    #![trigger post2_self_.pcid_to_proc_ptr(p)]
    post1_self_.pcid_active(p) implies
        post1_self_.pcid_to_proc_ptr(p) == post2_self_.pcid_to_proc_ptr(p)
by {
    // From the bridge above on `post1_self_.pcid_active(p)` we get
    // `post2_self_.pcid_active(p)`. The post1/post2 ensures then both
    // collapse `*_to_proc_ptr(p)` to `pre_self_.pcid_to_proc_ptr(p)`.
}

// get_pagetable_mapping_by_pcid matches for non-target pcids.
assert forall|p: Pcid|
    #![trigger post1_self_.get_pagetable_mapping_by_pcid(p)]
    #![trigger post2_self_.get_pagetable_mapping_by_pcid(p)]
    (post1_self_.pcid_active(p) && p != target_pcid) implies
        post1_self_.get_pagetable_mapping_by_pcid(p)
            == post2_self_.get_pagetable_mapping_by_pcid(p)
by {
    // The pcid_active bridge transfers activeness to post2; both
    // ensures then collapse `get_pagetable_mapping_by_pcid(p)` to
    // `pre_self_.get_pagetable_mapping_by_pcid(p)` when `p != target_pcid`.
}

// ioid_active matches between the two post-states.
assert forall|i: IOid|
    #![trigger post1_self_.ioid_active(i)]
    #![trigger post2_self_.ioid_active(i)]
    post1_self_.ioid_active(i) == post2_self_.ioid_active(i)
by {
    // Symmetric to the pcid_active bridge.
}

// ioid_to_proc_ptr matches when active.
assert forall|i: IOid|
    #![trigger post1_self_.ioid_to_proc_ptr(i)]
    #![trigger post2_self_.ioid_to_proc_ptr(i)]
    post1_self_.ioid_active(i) implies
        post1_self_.ioid_to_proc_ptr(i) == post2_self_.ioid_to_proc_ptr(i)
by {
    // Symmetric to the pcid_to_proc_ptr bridge.
}

// get_iommu_table_mapping_by_ioid matches when active.
assert forall|i: IOid|
    #![trigger post1_self_.get_iommu_table_mapping_by_ioid(i)]
    #![trigger post2_self_.get_iommu_table_mapping_by_ioid(i)]
    post1_self_.ioid_active(i) implies
        post1_self_.get_iommu_table_mapping_by_ioid(i)
            == post2_self_.get_iommu_table_mapping_by_ioid(i)
by {
    // Symmetric to the get_pagetable_mapping bridge, no target exclusion.
}
